def fit_hierarchical_regression_custom(df, demographic_vars, cognitive_vars, dependent_var):
    """
    Custom hierarchical regression implementation.
    
    Fits two models:
    1. Demographics only (age, sex, education)
    2. Full model (demographics + cognitive tests)
    
    Returns model comparison and coefficients with VIF.
    """
    
    # Prepare data
    X_demo = df[demographic_vars].copy()
    X_full = df[demographic_vars + cognitive_vars].copy()
    y = df[dependent_var].copy()
    
    # Handle categorical variables (sex)
    if 'sex' in X_demo.columns:
        # Convert to dummy if needed
        if X_demo['sex'].dtype == 'object':
            X_demo = pd.get_dummies(X_demo, columns=['sex'], drop_first=True)
            X_full = pd.get_dummies(X_full, columns=['sex'], drop_first=True)
    
    # Add constant
    X_demo_const = sm.add_constant(X_demo)
    X_full_const = sm.add_constant(X_full)
    
    # Fit models
    model_demo = sm.OLS(y, X_demo_const).fit()
    model_full = sm.OLS(y, X_full_const).fit()
    
    # Model comparison
    r2_demo = model_demo.rsquared
    r2_full = model_full.rsquared
    delta_r2 = r2_full - r2_demo
    
    # F-test for model comparison
    n = len(y)
    k_demo = len(demographic_vars) + 1  # +1 for constant
    k_full = len(demographic_vars + cognitive_vars) + 1
    k_diff = k_full - k_demo
    
    f_change = (delta_r2 / k_diff) / ((1 - r2_full) / (n - k_full - 1))
    p_change = 1 - stats.f.cdf(f_change, k_diff, n - k_full - 1)
    
    # Compute VIF for full model
    vif_data = []
    for i, col in enumerate(X_full_const.columns[1:]):  # Skip constant
        vif_val = variance_inflation_factor(X_full_const.values, i + 1)
        vif_data.append({'predictor': col, 'vif': vif_val})
    
    vif_df = pd.DataFrame(vif_data)
    
    # Model comparison results
    model_comparison = pd.DataFrame([
        {
            'model': 'Demographics',
            'r2': r2_demo,
            'adj_r2': model_demo.rsquared_adj,
            'delta_r2': np.nan,
            'f_change': np.nan,
            'p_value': np.nan,
            'aic': model_demo.aic,
            'bic': model_demo.bic
        },
        {
            'model': 'Full_Model',
            'r2': r2_full,
            'adj_r2': model_full.rsquared_adj,
            'delta_r2': delta_r2,
            'f_change': f_change,
            'p_value': p_change,
            'aic': model_full.aic,
            'bic': model_full.bic
        }
    ])
    
    return model_full, model_comparison, vif_df

def bootstrap_regression_ci_custom(X, y, n_bootstrap=1000, confidence_level=0.95, random_state=42):
    """
    Custom bootstrap confidence intervals for regression coefficients.
    """
    np.random.seed(random_state)
    
    n_samples, n_features = X.shape
    bootstrap_coeffs = np.zeros((n_bootstrap, n_features))
    
    alpha = 1 - confidence_level
    
    for i in range(n_bootstrap):
        # Bootstrap sample
        indices = resample(range(n_samples), n_samples=n_samples, random_state=random_state+i)
        X_boot = X.iloc[indices] if hasattr(X, 'iloc') else X[indices]
        y_boot = y.iloc[indices] if hasattr(y, 'iloc') else y[indices]
        
        # Fit model
        try:
            X_boot_const = sm.add_constant(X_boot)
            model_boot = sm.OLS(y_boot, X_boot_const).fit()
            bootstrap_coeffs[i] = model_boot.params[1:]  # Skip constant
        except:
            # Use NaN if bootstrap sample fails
            bootstrap_coeffs[i] = np.nan
    
    # Compute confidence intervals
    ci_lower = np.nanpercentile(bootstrap_coeffs, 100 * alpha/2, axis=0)
    ci_upper = np.nanpercentile(bootstrap_coeffs, 100 * (1 - alpha/2), axis=0)
    
    return ci_lower, ci_upper, bootstrap_coeffs

def validate_bootstrap_stability_custom(bootstrap_coeffs, min_jaccard_threshold=0.75):
    """
    Custom bootstrap stability validation using coefficient sign consistency.
    """
    n_bootstrap, n_features = bootstrap_coeffs.shape
    
    stability_results = {}
    
    for i in range(n_features):
        coeff_values = bootstrap_coeffs[:, i]
        valid_coeffs = coeff_values[~np.isnan(coeff_values)]
        
        if len(valid_coeffs) == 0:
            stability_results[f'feature_{i}'] = {
                'jaccard_index': 0.0,
                'sign_consistency': 0.0,
                'stable': False
            }
            continue
        
        # Sign consistency
        positive_count = np.sum(valid_coeffs > 0)
        negative_count = np.sum(valid_coeffs < 0)
        total_count = len(valid_coeffs)
        
        sign_consistency = max(positive_count, negative_count) / total_count
        
        # Approximate Jaccard index using coefficient magnitude stability
        median_coeff = np.median(valid_coeffs)
        mad = np.median(np.abs(valid_coeffs - median_coeff))
        cv = mad / (np.abs(median_coeff) + 1e-8)  # Avoid division by zero
        
        jaccard_approx = max(0, 1 - cv)  # Higher stability = lower CV
        
        is_stable = jaccard_approx >= min_jaccard_threshold
        
        stability_results[f'feature_{i}'] = {
            'jaccard_index': jaccard_approx,
            'sign_consistency': sign_consistency,
            'stable': is_stable
        }
    
    # Overall stability
    stable_features = sum(1 for v in stability_results.values() if v['stable'])
    overall_stable = stable_features >= len(stability_results) * 0.8  # 80% threshold
    
    return {
        'feature_stability': stability_results,
        'overall_stable': overall_stable,
        'stable_feature_count': stable_features,
        'total_features': len(stability_results)
    }

