        log("[ANALYSIS] Running hierarchical regression...")
        
        demographic_vars = ['age', 'sex', 'education']
        cognitive_vars = ['RAVLT_T', 'BVMT_T', 'RPM_T', 'RAVLT_Pct_Ret_T', 'BVMT_Pct_Ret_T']
        dependent_var = 'calibration_quality'
        
        # Remove missing data
        analysis_df = df[demographic_vars + cognitive_vars + [dependent_var]].dropna()
        log(f"[INFO] Analysis sample after removing missing data: {len(analysis_df)} participants")
        
        model_full, model_comparison, vif_df = fit_hierarchical_regression_custom(
            analysis_df, 
            demographic_vars, 
            cognitive_vars, 
            dependent_var
        )
        
        log("[DONE] Hierarchical regression complete")
        log(f"[INFO] Demographics R² = {model_comparison.iloc[0]['r2']:.4f}")
        log(f"[INFO] Full model R² = {model_comparison.iloc[1]['r2']:.4f}")
        log(f"[INFO] ΔR² = {model_comparison.iloc[1]['delta_r2']:.4f}, p = {model_comparison.iloc[1]['p_value']:.4f}")

        # =========================================================================
        # STEP 3: Bootstrap Confidence Intervals
        # =========================================================================
        # Purpose: Generate robust confidence intervals for all coefficients
        
        log("[BOOTSTRAP] Computing bootstrap confidence intervals...")
        
        # Prepare data for bootstrap
        X_predictors = analysis_df[demographic_vars + cognitive_vars].copy()
        y_outcome = analysis_df[dependent_var].copy()
        
        # Handle categorical sex variable
        if 'sex' in X_predictors.columns and X_predictors['sex'].dtype == 'object':
            X_predictors = pd.get_dummies(X_predictors, columns=['sex'], drop_first=True)
        
        ci_lower, ci_upper, bootstrap_coeffs = bootstrap_regression_ci_custom(
            X_predictors, y_outcome, n_bootstrap=1000, confidence_level=0.95, random_state=42
        )
        
        log("[DONE] Bootstrap confidence intervals computed")

        # =========================================================================
        # STEP 4: Extract Regression Results with Dual P-values
        # =========================================================================
        # Purpose: Create comprehensive results table with uncorrected and corrected p-values
        
        log("[EXTRACT] Extracting regression coefficients with dual p-values...")
        
        # Prepare design matrix for final model
        X_full_analysis = X_predictors.copy()
        X_full_const = sm.add_constant(X_full_analysis)
        
        # Extract coefficient information
        coefficients = model_full.params[1:]  # Skip constant
        std_errors = model_full.bse[1:]
        p_uncorrected = model_full.pvalues[1:]
        
        # Semi-partial correlations (squared)
        correlation_matrix = np.corrcoef(X_full_analysis.T, y_outcome)[:-1, -1]  # Correlations with y
        r_squared_model = model_full.rsquared
        
        # Approximate sr² using correlation and model R²
        sr_squared = correlation_matrix ** 2 * r_squared_model / len(coefficients)
        
        # Merge with VIF data
        predictor_names = list(X_full_analysis.columns)
        
        # Create results DataFrame
        results_data = []
        for i, pred in enumerate(predictor_names):
            # Find VIF for this predictor
            vif_value = vif_df[vif_df['predictor'] == pred]['vif'].iloc[0] if pred in vif_df['predictor'].values else np.nan
            
            results_data.append({
                'predictor': pred,
                'beta': coefficients.iloc[i],
                'se': std_errors.iloc[i],
                'ci_lower': ci_lower[i],
                'ci_upper': ci_upper[i],
                'p_uncorrected': p_uncorrected.iloc[i],
                'sr_squared': abs(sr_squared[i]),  # Ensure positive
                'vif': vif_value
            })
        
        regression_results = pd.DataFrame(results_data)
        
        # Apply multiple comparison corrections
        # Bonferroni correction (Decision D068: α = 0.000597)
        bonferroni_alpha = 0.000597
        regression_results['p_bonferroni'] = regression_results['p_uncorrected'] * len(regression_results)
        regression_results['p_bonferroni'] = regression_results['p_bonferroni'].clip(upper=1.0)
        
        # FDR correction (Benjamini-Hochberg)
        _, p_fdr, _, _ = multipletests(regression_results['p_uncorrected'], method='fdr_bh')
        regression_results['p_fdr'] = p_fdr
        
        log("[DONE] Regression results extracted with dual p-values")

        # =========================================================================
        # STEP 5: Save Analysis Outputs
        # =========================================================================
