        regression_results.to_csv(RQ_DIR / "data" / "step04_regression_results.csv", index=False, encoding='utf-8')
        log(f"[SAVED] step04_regression_results.csv ({len(regression_results)} rows, {len(regression_results.columns)} cols)")
        
        # Output: step04_model_comparison.csv  
        # Contains: Model comparison statistics for hierarchical blocks
        model_comparison.to_csv(RQ_DIR / "data" / "step04_model_comparison.csv", index=False, encoding='utf-8')
        log(f"[SAVED] step04_model_comparison.csv ({len(model_comparison)} rows, {len(model_comparison.columns)} cols)")

        # =========================================================================
        # STEP 6: Run Validation Tool
        # =========================================================================
        # Tool: Custom bootstrap stability validation
        # Validates: Bootstrap coefficient stability and sign consistency
        # Threshold: Jaccard index >= 0.75 for stability

        log("[VALIDATION] Running bootstrap stability validation...")
        validation_result = validate_bootstrap_stability_custom(
            bootstrap_coeffs, min_jaccard_threshold=0.75
        )

        # Report validation results
        # Expected: High bootstrap stability indicates reliable coefficient estimates
        log(f"[VALIDATION] Overall bootstrap stability: {validation_result['overall_stable']}")
        log(f"[VALIDATION] Stable features: {validation_result['stable_feature_count']}/{validation_result['total_features']}")
        
        for feature, stability in validation_result['feature_stability'].items():
            pred_name = predictor_names[int(feature.split('_')[1])] if feature.startswith('feature_') else feature
            log(f"[VALIDATION] {pred_name}: Jaccard={stability['jaccard_index']:.3f}, Sign={stability['sign_consistency']:.3f}, Stable={stability['stable']}")

